def replace_emojis(filename):
    with open(filename, 'r', encoding='utf-8') as f:
        content = f.read()
    for emoji, svg in icons.items():
        content = content.replace(emoji, svg)
    with open(filename, 'w', encoding='utf-8') as f:
        f.write(content)

